1	import { describe, it, expect } from "vitest";
2	import { quote } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  describe("quote - base premiums", () => {
6	    it("returns 5G processing fee for empty item list", () => {
7	      const result = quote({ yearsWithMHPCO: 0 }, [], false);
8	      expect(result).toBe(5);
9	    });
10	    it.todo("returns base premium plus fee for a single sword (100 + 5 = 105)");
11	    it.todo("returns base premium plus fee for a single amulet (60 + 5 = 65)");
12	    it.todo("returns base premium plus fee for a single staff (80 + 5 = 85)");
13	    it.todo("returns base premium plus fee for a single potion (40 + 5 = 45)");
14	    it.todo("sums base premiums for multiple items plus fee");
15	  });
16	
17	  describe("quote - component premiums", () => {
18	    it.todo("returns 25G base premium per component (e.g. 2 runes = 50)");
19	    it.todo("applies block discount for exactly 3 alike components (3 runes = 60)");
20	    it.todo("does not apply block for 4 alike components (4 runes = 100)");
21	    it.todo("does not apply block for 3 components of different types (2 runes + 1 moonstone = 75)");
22	    it.todo("applies separate blocks for 3 runes and 3 moonstones (120)");
23	  });
24	
25	  describe("quote - item-level modifiers", () => {
26	    it.todo("adds 50% cursed surcharge to the cursed item's base premium only");
27	    it.todo("adds 30% high-enchantment surcharge for enchantment level >= 5");
28	    it.todo("applies both cursed and high-enchantment surcharges to the same item");
29	    it.todo("does not apply high-enchantment surcharge for enchantment level 4");
30	  });
31	
32	  describe("quote - policy-level modifiers", () => {
33	    it.todo("applies 10% first-insurance surcharge on the policy base premium");
34	    it.todo("applies 20% loyalty discount for customer with >= 2 years");
35	    it.todo("applies 15% follow-up discount on second quote");
36	    it.todo("applies first-insurance surcharge even for long-standing customers");
37	  });
38	
39	  describe("quote - rounding", () => {
40	    it.todo("rounds premium up in MHPCO's favor (ceiling)");
41	  });
42	
43	  describe("quote - integration", () => {
44	    it.todo("newcomer with cursed sword: 165G");
45	    it.todo("long-standing customer second contract with cursed high-enchantment sword: 160G");
46	  });
47	
48	  describe("claim - basic payout", () => {
49	    it.todo("applies 100G deductible per damaged item");
50	    it.todo("fully reimburses dragon-material item damage minus deductible");
51	    it.todo("reimburses at 50% for enchantment >= 8 then applies deductible");
52	    it.todo("applies 50% rule when both dragon material and enchantment >= 8");
53	    it.todo("does not apply enchantment clause for enchantment < 8");
54	  });
55	
56	  describe("claim - cap", () => {
57	    it.todo("caps total payout at twice the insurance sum");
58	    it.todo("tracks remaining cap across successive claims on same policy");
59	  });
60	
61	  describe("claim - multiple items", () => {
62	    it.todo("applies deductible separately per damaged item in same event");
63	    it.todo("handles damage to component (rune) with deductible");
64	  });
65	
66	  describe("claim - rounding", () => {
67	    it.todo("rounds payout down in MHPCO's favor (floor)");
68	  });
69	
70	  describe("error handling", () => {
71	    it.todo("rejects unknown item type in quote");
72	    it.todo("rejects claim for item not in policy");
73	    it.todo("rejects claim with more damage entries than insured items of that type");
74	    it.todo("rejects negative damage amount");
75	  });
76	
77	  describe("CLI integration", () => {
78	    it.todo("reads scenario JSON from stdin and writes results JSON to stdout");
79	    it.todo("processes sequential quote and claim steps referencing policy by index");
80	  });
81	});
